SELECT id AS id ,user_id AS userId ,email_address AS emailAddress ,nick_name AS nickName ,approved AS approved ,approved_at AS approvedAt ,admin AS admin ,blocked AS blocked ,created_at AS createdAt ,updated_at AS updatedAt FROM genesis_user WHERE deleted = FALSE
AND email_address LIKE '%${emailAddress}%'
AND approved = #{approved}
ORDER BY id DESC
LIMIT 0, #{size} LIMIT #{offset}, #{size}

