UPDATE genesis_user
SET
   nick_name    = #{nickName}
  ,updated_at   = #{updatedAt}
  ,updated_by   = #{updatedBy}
WHERE
  id            = #{id}
  AND
  user_id       = #{userId}
  AND
  email_address = #{emailAddress}

UPDATE genesis_user
SET
   approved     = #{approved}
  ,approved_at  = #{approvedAt}
  ,updated_at   = #{updatedAt}
  ,updated_by   = #{updatedBy}
WHERE
  id      = #{id}
  AND
  user_id = #{userId}

UPDATE genesis_user
SET
   blocked      = #{blocked}
  ,updated_at   = #{updatedAt}
  ,updated_by   = #{updatedBy}
WHERE
  id      = #{id}
  AND
  user_id = #{userId}

UPDATE genesis_user
SET
   admin        = #{admin}
  ,updated_at   = #{updatedAt}
  ,updated_by   = #{updatedBy}
WHERE
  id      = #{id}
  AND
  user_id = #{userId}
